```typescript
function solve(nums: number[]): boolean {
    const n = nums.length;
    for (let p = 1; p <= n - 3; p++) {
        // Check if the first part is strictly increasing
        let validFirst = true;
        for (let i = 0; i < p; i++) {
            if (nums[i] >= nums[i + 1]) {
                validFirst = false;
                break;
            }
        }
        if (!validFirst) continue;

        // Find the maximum q where nums[p...q] is strictly decreasing
        let current_q = p;
        for (let i = p; i < n - 1; i++) {
            if (nums[i] > nums[i + 1]) {
                current_q = i + 1;
            } else {
                break;
            }
        }

        // Check if current_q is valid
        if (current_q <= p || current_q >= n - 1) {
            continue;
        }

        // Check if the third part is strictly increasing
        let validThird = true;
        for (let i = current_q; i < n - 1; i++) {
            if (nums[i] >= nums[i + 1]) {
                validThird = false;
                break;
            }
        }
        if (validThird) {
            return true;
        }
    }
    return false;
}
```

