function solve(nums: number[]): boolean {
    const n = nums.length;
    for (let p = 1; p < n - 1; p++) {
        // Check if the first part is strictly increasing
        let validFirst = true;
        for (let i = 0; i < p; i++) {
            if (nums[i] >= nums[i + 1]) {
                validFirst = false;
                break;
            }
        }
        if (!validFirst) continue;

        // Find the maximum q where nums[p...q] is strictly decreasing
        let currentQ = p;
        for (let i = p; i < n - 1; i++) {
            if (nums[i] > nums[i + 1]) {
                currentQ = i + 1;
            } else {
                break;
            }
        }

        // Check if q is valid (p < q < n - 1)
        if (currentQ <= p || currentQ >= n - 1) {
            continue;
        }

        // Check if the third part is strictly increasing
        let validThird = true;
        for (let i = currentQ; i < n - 1; i++) {
            if (nums[i] >= nums[i + 1]) {
                validThird = false;
                break;
            }
        }
        if (validThird) {
            return true;
        }
    }
    return false;
}
